import React from 'react';
// Importa createRoot para React 18+ si lo estás usando (recomendado)
import ReactDOM from 'react-dom/client'; 
import './index.css';
// ✅ CORRECCIÓN AQUÍ: Cambia la ruta para App.js
import App from './components/App'; 

// Utiliza createRoot para React 18+ (la forma moderna)
const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
    <App /> {/* ¡Solo renderiza el componente App! */}
  </React.StrictMode>
);

// Si estás usando una versión anterior de React (17 o inferior), usa esta sintaxis en su lugar:
/*
import ReactDOM from 'react-dom';
ReactDOM.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
  document.getElementById('root')
);
